# ── PDF generators ────────────────────────────────────────────────────────────
def pdf_narrative(dispute, user, loc, verdict, act_summary, active_dates, last_active, all_locations=None, charge_history=None, signals=None):
    buf = io.BytesIO()
    doc = make_doc(buf, "Dispute Narrative")
    s = []
    doc_header(s, dispute["dispute_id"])
    section_badge(s, "1.", "Dispute Narrative", "Other", INDIGO_LT, INDIGO_BDR, colors.HexColor("#1e3a5f"))
    v_label, v_bg, v_bdr, v_col = VERDICT_STYLES.get(verdict, VERDICT_STYLES["NO_DATA"])
    r              = (dispute.get("reason") or "general").lower()
    reason_display = r.replace("_"," ").title()
    s.append(tip_box("VERDICT: " + v_label + "  |  Dispute reason: " + reason_display, v_bg, v_bdr, v_col))
    s.append(Spacer(1,14))
    s.append(sh("Dispute Statement"))
    name    = dispute.get("customer_name") or ((str(user.get("first_name") or "") + " " + str(user.get("last_name") or "")).strip() if user else "--")
    email   = dispute.get("customer_email","--")
    company = loc.get("name","--") if loc else "--"
    amount  = dispute.get("amount","--")
    created = fmt(loc.get("created_at")) if loc else "--"
    t_act   = act_summary.get("total_active_days") or 0
    m_act   = act_summary.get("mobile_active_days") or 0
    w_act   = act_summary.get("web_active_days") or 0
    web_si  = user.get("web_sign_in_count",0) if user else 0
    signins = max(user.get("sign_in_count",0) or 0, web_si) if user else 0
    best_last_active = (user.get("last_sign_in_at") or
                        user.get("mobile_last_used_at")) if user else None
    if best_last_active and last_active == "--":
        last_active = fmt(best_last_active)
    paras = get_reason_content(dispute.get("reason"), name, email, company, amount, created,
                               t_act, w_act, m_act, signins, web_si, last_active,
                               all_locations, dispute, user, verdict)
    for p in paras:
        s.append(bp(p))
        s.append(Spacer(1,6))
    s.append(Spacer(1,14))
    s.append(sh("Account Summary"))
    s.append(kv_table([
        ("Customer", name), ("Email", email), ("Company", company),
        ("Dispute ID", dispute.get("dispute_id","--")), ("Amount", amount),
        ("Reason", reason_display), ("Status", dispute.get("status","--")),
        ("Evidence Due", fmt(dispute.get("evidence_due_date"))),
    ]))
    # Activity logs appended directly to narrative
    s.append(Spacer(1, 20))
    s.append(HRFlowable(width="100%", thickness=1, color=GRAY_BDR))
    s.append(Spacer(1, 14))
    s.append(sh("Platform Activity Logs"))
    s.append(kv_table([
        ("Total Active Days",         str(act_summary.get("total_active_days") or 0)),
        ("Days with Web Activity",    str(act_summary.get("web_active_days") or 0)),
        ("Days with Mobile Activity", str(act_summary.get("mobile_active_days") or 0)),
        ("Days with Scheduling",      str(act_summary.get("scheduling_active_days") or 0)),
        ("Last Recorded Activity",    last_active),
    ]))
    s.append(Spacer(1, 14))
    if active_dates:
        s.append(sh("Active Dates Since Account Creation"))
        rows_act = [[d, "Active"] for d in active_dates[:50]]
        s.append(grid_table(rows_act, ["Date", "Status"], cw=[3.5*inch, 3.5*inch]))
        if len(active_dates) > 50:
            s.append(Spacer(1, 6))
            s.append(bp("... and " + str(len(active_dates) - 50) + " additional active dates."))
    else:
        s.append(bp("No activity records found for this account."))
    s.append(Spacer(1, 14))
    if r == "fraudulent":
        act_tip = ("Key evidence: The sustained login history and platform usage is inconsistent "
                   "with an unauthorized account. A fraudster would not maintain this level of engagement.")
    elif r == "product_not_received":
        act_tip = ("Key evidence: As a SaaS product, Homebase is delivered digitally. The activity "
                   "logs prove the customer had full, uninterrupted access during the disputed period.")
    elif r == "product_unacceptable":
        act_tip = ("Key evidence: Continued platform usage is inconsistent with a claim that the "
                   "product was unacceptable. No complaint was filed prior to the chargeback.")
    else:
        act_tip = ("Key evidence: The customer actively used Homebase on the dates listed above, "
                   "demonstrating the service was actively rendered and received.")
    s.append(tip_box(act_tip, AMBER_LT, AMBER_BDR, AMBER))
    # Prior charge history section (especially useful for fraudulent disputes)
    if charge_history:
        s.append(Spacer(1, 18))
        s.append(HRFlowable(width="100%", thickness=1, color=GRAY_BDR))
        s.append(Spacer(1, 14))
        s.append(sh("Prior Successful Charge History"))
        s.append(bp("The following invoices show a consistent pattern of successful charges "
                    "to this account prior to the disputed charge, demonstrating an established "
                    "and authorized billing relationship."))
        s.append(Spacer(1, 8))

        def ts_to_date_n(val):
            if not val or val == "--": return "--"
            try:
                from datetime import datetime, timezone
                return datetime.fromtimestamp(int(val), tz=timezone.utc).strftime("%Y-%m-%d")
            except (ValueError, TypeError):
                return str(val)[:10]

        ch_rows = []
        for ch in charge_history:
            ch_rows.append([
                ts_to_date_n(ch.get("created")),
                ch.get("number","--"),
                fmt_amount(ch.get("amount_paid")),
                (ch.get("billing_reason") or "--").replace("_"," ").title(),
                (ch.get("status") or "--").title(),
            ])
        s.append(grid_table(ch_rows,
            ["Date", "Invoice", "Amount", "Billing Reason", "Status"],
            cw=[1.0*inch, 1.5*inch, 0.9*inch, 2.1*inch, 0.8*inch]))
        s.append(Spacer(1, 10))
        s.append(tip_box(
            "Key evidence: " + str(len(charge_history)) + " prior successful charge(s) to this account "
            "confirm an established, authorized billing relationship. The disputed charge follows "
            "the same recurring pattern as all prior charges.",
            GREEN_LT, GREEN_BDR, GREEN))

    add_footer(s)
    doc.build(s)
    buf.seek(0)
    return buf.read()

def fmt_amount(val):
    """Convert cents string to dollar string."""
    if not val or val == "--":
        return "--"
    try:
        return "$" + "{:.2f}".format(int(val) / 100)
    except (ValueError, TypeError):
        return str(val)

def pdf_receipt(dispute, invoices=None):
    buf = io.BytesIO()
    doc = make_doc(buf, "Dispute Details & Receipt")
    s = []
    doc_header(s, dispute["dispute_id"])
    section_badge(s, "2.", "Dispute Details & Receipt", "Receipt",
                  colors.HexColor("#f5f3ff"), colors.HexColor("#ddd6fe"), colors.HexColor("#5b21b6"))

    # Dispute summary
    s.append(sh("Dispute Summary"))
    s.append(kv_table([
        ("Dispute ID",    dispute.get("dispute_id","--")),
        ("Status",        dispute.get("status","--")),
        ("Reason",        (dispute.get("reason") or "").replace("_"," ").title()),
        ("Amount",        dispute.get("amount","--")),
        ("Customer Name", dispute.get("customer_name","--")),
        ("Customer Email",dispute.get("customer_email","--")),
        ("Evidence Due",  fmt(dispute.get("evidence_due_date"))),
    ]))
    s.append(Spacer(1,18))

    # Invoice receipt for this specific dispute
    s.append(sh("Invoice Receipt"))
    inv = invoices  # single invoice dict or None
    if inv:
        # Convert unix timestamps to readable dates for period
        def ts_to_date(val):
            if not val or val == "--":
                return "--"
            try:
                from datetime import datetime, timezone
                return datetime.fromtimestamp(int(val), tz=timezone.utc).strftime("%Y-%m-%d")
            except (ValueError, TypeError):
                return str(val)[:10]

        s.append(kv_table([
            ("Invoice Number",  inv.get("number","--")),
            ("Invoice ID",      inv.get("id","--")),
            ("Status",          (inv.get("status") or "--").title()),
            ("Billing Reason",  (inv.get("billing_reason") or "--").replace("_"," ").title()),
            ("Amount Due",      fmt_amount(inv.get("amount_due"))),
            ("Amount Paid",     fmt_amount(inv.get("amount_paid"))),
            ("Currency",        (inv.get("currency") or "usd").upper()),
            ("Service Period",  ts_to_date(inv.get("period_start")) + " to " + ts_to_date(inv.get("period_end"))),
            ("Invoice Date",    ts_to_date(inv.get("created"))),
            ("Receipt Number",  inv.get("receipt_number") or "--"),
            ("Subscription ID", inv.get("subscription","--")),
            ("Charge ID",       inv.get("charge","--")),
        ]))
        if inv.get("hosted_invoice_url"):
            s.append(Spacer(1,8))
            s.append(tip_box(
                "Invoice URL: " + inv.get("hosted_invoice_url"),
                GREEN_LT, GREEN_BDR, GREEN))
    else:
        s.append(tip_box(
            "No matching invoice found in the database for this dispute amount. "
            "Retrieve the invoice PDF from Stripe Dashboard > Customers > " +
            dispute.get("customer_email","") + " and attach alongside this document.",
            INDIGO_LT, INDIGO_BDR, colors.HexColor("#1e3a5f")))

    add_footer(s)
    doc.build(s)
    buf.seek(0)
    return buf.read()

def pdf_service_docs(dispute, user, loc, plan_history, all_locs=None):
    buf = io.BytesIO()
    doc = make_doc(buf, "Service Documentation")
    s = []
    doc_header(s, dispute["dispute_id"])
    section_badge(s, "3.", "Service Documentation", "Service documentation", GREEN_LT, GREEN_BDR, GREEN)
    owner    = ((str(user.get("first_name") or "") + " " + str(user.get("last_name") or "")).strip() if user else "--")
    archived = loc.get("archived_at") if loc else None
    s.append(sh("Account Overview"))
    s.append(kv_table([
        ("Company ID",    str(loc.get("company_id","--")) if loc else "--"),
        ("Owner",         owner),
        ("Billing Source",loc.get("billing_source","--") if loc else "--"),
    ], cw=[2.0*inch, 5.0*inch]))
    s.append(Spacer(1, 12))

    # Show all locations in a table
    locs_to_show = all_locs if all_locs else ([loc] if loc else [])
    s.append(sh("Locations (" + str(len(locs_to_show)) + " total)"))
    loc_rows = []
    for l in locs_to_show[:100]:
        status = "Active" if not l.get("archived_at") else "Canceled " + fmt(l.get("archived_at"))
        loc_rows.append([
            l.get("name","--"),
            str(l.get("location_id","--")),
            fmt(l.get("created_at")),
            status,
            tier_name(l.get("tier_id")),
        ])
    s.append(grid_table(loc_rows,
        ["Location Name", "ID", "Created", "Status", "Plan"],
        cw=[2.2*inch, 0.8*inch, 1.0*inch, 1.6*inch, 1.2*inch]))
    if len(locs_to_show) > 100:
        s.append(Spacer(1, 4))
        s.append(bp("... and " + str(len(locs_to_show) - 100) + " additional locations not shown."))
    s.append(Spacer(1, 10))

    # Count never-canceled locations
    never_canceled = [l for l in locs_to_show if not l.get("archived_at")]
    s.append(tip_box(
        "Key evidence: " + str(len(never_canceled)) + " of " + str(len(locs_to_show)) +
        " location(s) have archived_at = NULL, confirming no cancellation was ever processed "
        "for those locations. In Homebase, cancellation sets archived_at to the cancellation "
        "timestamp. Its absence is definitive proof the account remains active.",
        GREEN_LT, GREEN_BDR, GREEN))
    s.append(Spacer(1,12))
    s.append(sh("Owner Sign-In History"))
    if user:
        # Use best available last sign-in date across all fields
        last_si = (user.get("last_sign_in_at") or
                   user.get("mobile_last_used_at"))
        web_si = user.get("web_sign_in_count") or 0
        signin_rows = [
            ("Web Sign-Ins (all time)",  str(web_si)),
            ("Last Recorded Sign-In",    fmt(last_si) if last_si else "--"),
        ]
        if user.get("mobile_last_used_at"):
            mob_label = "Last Mobile Activity"
            mob_val   = fmt(user.get("mobile_last_used_at"))
            if user.get("mobile_last_used_info"):
                mob_val = mob_val + " (" + str(user.get("mobile_last_used_info")) + ")"
            signin_rows.append((mob_label, mob_val))
        s.append(kv_table(signin_rows))
    else:
        s.append(bp("No sign-in data available."))
    s.append(Spacer(1,18))
    s.append(HRFlowable(width="100%", thickness=1, color=GRAY_BDR))
    s.append(Spacer(1,18))
    s.append(sh("Subscription & Plan Change History"))
    if plan_history:
        rows = [[fmt(e.get("created_at")), 
                 str(e.get("location_id","--")),
                 e.get("type") or "subscription",
                 str(e.get("start_tier","?")) + " to " + str(e.get("end_tier","?")),
                 str(e.get("old_subscription_type") or "--") + " to " + str(e.get("new_subscription_type") or "--")]
                for e in plan_history]
        s.append(grid_table(rows, ["Date","Location ID","Event","Tier Change","Plan Change"],
                            cw=[1.1*inch,0.9*inch,1.1*inch,1.2*inch,2.4*inch]))
    else:
        s.append(bp("No subscription change history found."))
    s.append(Spacer(1,10))
    # Dynamically summarize plan history
    has_downgrades = any(e.get("type") == "downgrade" for e in plan_history)
    has_cancels    = any("cancel" in str(e.get("type") or "").lower() for e in plan_history)
    if not has_downgrades and not has_cancels:
        plan_tip = ("Key evidence: No downgrade or cancellation events appear in the subscription "
                    "history. The account has been continuously active since creation.")
        tip_col = GREEN
    elif has_downgrades and not has_cancels:
        plan_tip = ("Note: The subscription history shows tier changes (upgrades/downgrades) "
                    "but no cancellation events. The account has never been canceled. "
                    "Tier changes are normal and do not indicate cancellation.")
        tip_col = AMBER
    else:
        plan_tip = ("Note: The subscription history contains changes. Review the table above "
                    "to confirm the account status at the time of the disputed charge.")
        tip_col  = AMBER
    tip_bg  = GREEN_LT if tip_col == GREEN else AMBER_LT
    tip_bdr = GREEN_BDR if tip_col == GREEN else AMBER_BDR
    s.append(tip_box(plan_tip, tip_bg, tip_bdr, tip_col))
    add_footer(s)
    doc.build(s)
    buf.seek(0)
    return buf.read()

def pdf_activity(dispute, act_summary, active_dates, last_active):
    buf = io.BytesIO()
    doc = make_doc(buf, "Customer Activity")
    s = []
    doc_header(s, dispute["dispute_id"])
    section_badge(s, "4.", "Customer Activity Logs", "Customer communication", AMBER_LT, AMBER_BDR, AMBER)
    s.append(sh("Activity Summary During Disputed Period"))
    s.append(kv_table([
        ("Total Active Days", str(act_summary.get("total_active_days") or 0)),
        ("Days with Web Activity", str(act_summary.get("web_active_days") or 0)),
        ("Days with Mobile Activity", str(act_summary.get("mobile_active_days") or 0)),
        ("Days with Scheduling Activity", str(act_summary.get("scheduling_active_days") or 0)),
        ("Last Recorded Activity", last_active),
    ]))
    s.append(Spacer(1,14))
    if active_dates:
        s.append(sh("Active Dates During Disputed Period"))
        rows = [[d, "Active"] for d in active_dates[:50]]
        s.append(grid_table(rows, ["Date","Status"], cw=[3.5*inch,3.5*inch]))
        if len(active_dates) > 50:
            s.append(Spacer(1,6))
            s.append(bp("... and " + str(len(active_dates)-50) + " additional active dates."))
    else:
        s.append(bp("No activity records found for this period."))
    s.append(Spacer(1,14))
    r = (dispute.get("reason") or "").lower()
    if r == "fraudulent":
        tip_text = ("Key evidence: The volume and consistency of logins is inconsistent with "
                    "an unauthorized account. A fraudster would not maintain this level of ongoing engagement.")
    elif r == "product_not_received":
        tip_text = ("Key evidence: As a SaaS product, Homebase is delivered digitally. The activity "
                    "logs prove the customer had full, uninterrupted access during the disputed period.")
    elif r == "product_unacceptable":
        tip_text = ("Key evidence: Continued platform usage during the disputed period is inconsistent "
                    "with a claim that the product was unacceptable.")
    else:
        tip_text = ("Key evidence: The customer actively used the Homebase platform on the dates listed "
                    "above during the disputed billing period, demonstrating the service was rendered.")
    s.append(tip_box(tip_text, AMBER_LT, AMBER_BDR, AMBER))
    add_footer(s)
    doc.build(s)
    buf.seek(0)
    return buf.read()

def pdf_policy(dispute, loc):
    buf = io.BytesIO()
    doc = make_doc(buf, "Refund Policy")
    s = []
    doc_header(s, dispute["dispute_id"])
    section_badge(s, "5.", "Refund & Cancellation Policy", "Refund and cancellation policy",
                  GREEN_LT, GREEN_BDR, GREEN)
    s.append(sh("Homebase Cancellation & Refund Policy"))
    s.append(bp("Effective for all Homebase subscriptions at joinhomebase.com"))
    s.append(Spacer(1,10))
    for heading, body in [
        ("CANCELLATION",
         "Customers may cancel their Homebase subscription at any time by logging into "
         "their account and navigating to Settings > Billing & Plan > Cancel Subscription. "
         "Cancellations must be initiated by the account owner within the Homebase application. "
         "Homebase does not accept cancellation requests via email or phone. Upon cancellation "
         "the account remains active through the end of the billing period."),
        ("REFUND POLICY",
         "Homebase offers a 30-day full refund policy. The 30-day window is calculated from "
         "the date of each individual charge -- not the account signup date. Applies to both "
         "monthly and annual plans. Canceling within 30 days of a charge = full refund of "
         "that charge. Not canceling within 30 days = no refund. No prorated refunds are "
         "issued under any circumstances."),
    ]:
        s.append(Paragraph("<b>" + heading + "</b>", ParagraphStyle("hd", fontName="Helvetica-Bold",
            fontSize=10, textColor=DARK, spaceBefore=8, spaceAfter=4)))
        s.append(bp(body))
        s.append(Spacer(1,6))
    s.append(Paragraph("<b>HOW TO CANCEL</b>", ParagraphStyle("hd2", fontName="Helvetica-Bold",
        fontSize=10, textColor=DARK, spaceBefore=8, spaceAfter=4)))
    for step in ["1.  Log in at app.joinhomebase.com", "2.  Navigate to Settings > Billing & Plan",
                 "3.  Click Manage Plan or Cancel Subscription",
                 "4.  Confirm -- email confirmation sent immediately"]:
        s.append(bp(step))
    s.append(Spacer(1, 14))

    # Embed cancellation screenshots as visual evidence
    s.append(sh("Visual Guide: How Cancellation Works in Homebase"))
    # Tailor the screenshot description to the dispute reason
    r_pol = (dispute.get("reason") or "").lower()
    if r_pol in ("subscription_canceled", "credit_not_processed", "debit_not_authorized"):
        screenshot_context = ("The following screenshots show the cancellation flow inside the Homebase app. "
                              "A customer must actively navigate to Settings > Plan & Billing and click "
                              "Delete Company or Submit Cancellation Request. No such action was ever "
                              "taken for the disputed account.")
    elif r_pol in ("fraudulent", "unrecognized", "debit_not_authorized"):
        screenshot_context = ("The following screenshots show the cancellation flow inside the Homebase app. "
                              "This demonstrates that cancellation requires a deliberate, multi-step "
                              "in-app action by the account owner -- confirming the account was "
                              "knowingly maintained as an active subscription.")
    elif r_pol == "duplicate":
        screenshot_context = ("The following screenshots show the cancellation flow inside the Homebase app. "
                              "Each location must be canceled individually. No cancellation was submitted "
                              "for any of the disputed locations.")
    else:
        screenshot_context = ("The following screenshots show the cancellation flow inside the Homebase app. "
                              "Cancellation requires a deliberate in-app action by the account owner. "
                              "This process was not initiated for the disputed account.")
    s.append(bp(screenshot_context))
    s.append(Spacer(1, 10))

    from reportlab.platypus import Image as RLImage
    import io as _io

    for label, b64_data in [
        ("Step 1: Navigate to Settings > Plan & Billing > Delete Company", _STEP1_IMG_B64),
        ("Step 2: Submit Cancellation Request form", _STEP2_IMG_B64),
    ]:
        if not b64_data:
            continue
        s.append(Paragraph("<b>" + label + "</b>",
                           ParagraphStyle("sl", fontName="Helvetica-Bold", fontSize=9,
                                          textColor=DARK, spaceAfter=6)))
        img_bytes = _b64.b64decode(b64_data)
        img_buf   = _io.BytesIO(img_bytes)
        # Aspect ratio: original 1100 x 850 approx
        img       = RLImage(img_buf, width=6.5*inch, height=5.02*inch)
        s.append(img)
        s.append(Spacer(1, 14))

    s.append(Spacer(1, 4))
    archived = loc.get("archived_at") if loc else None
    r = (dispute.get("reason") or "").lower()
    if r in ("fraudulent","debit_not_authorized","unrecognized"):
        closing = ("Evidence in this dispute: This was a legitimate, authorized charge. "
                   "The account " + dispute.get("customer_email","") + " has been actively used. "
                   "The charge of " + dispute.get("amount","--") + " is fully valid.")
    else:
        closing = ("Evidence in this dispute: No cancellation was initiated for "
                   + dispute.get("customer_email","this account") + ". "
                   "archived_at = " + ("NULL" if not archived else fmt(archived)) + ". "
                   "The customer did not cancel within 30 days of the disputed charge of "
                   + dispute.get("amount","--") + " -- and has never canceled at all. "
                   "The charge is fully valid and non-refundable.")
    s.append(tip_box(closing, RED_LT, RED_BDR, RED))
    add_footer(s)
    doc.build(s)
    buf.seek(0)
    return buf.read()

# ── Main pipeline ─────────────────────────────────────────────────────────────
def build_package(dispute_id):
    from datetime import date, timedelta, datetime
    dispute = get_dispute(dispute_id)
    if not dispute:
        raise ValueError("No dispute found for ID: " + dispute_id)
    customer_email = dispute.get("customer_email")
    if not customer_email:
        raise ValueError("Dispute record has no customer_email.")
    user, loc, all_locs = get_account(customer_email)
    if not loc:
        raise ValueError("No Homebase account found for: " + customer_email)
    company_id    = loc["company_id"]
    plan_history  = get_plan_history(company_id)
    all_locations = all_locs  # already fetched in get_account
    created = str(dispute.get("created_at") or "")[:10]
    # Use account creation date as period start to capture all activity
    # Fall back to 12 months ago if we cant determine account age
    loc_created = fmt(loc.get("created_at")) if loc else "--"
    if loc_created and loc_created != "--":
        period_start = loc_created
    elif created and created not in ("--",""):
        center       = datetime.strptime(created, "%Y-%m-%d").date()
        period_start = str(center - timedelta(days=365))
    else:
        period_start = str(date.today() - timedelta(days=365))
    period_end = str(date.today())
    act_summary, active_dates, last_active = get_activity(company_id, period_start, period_end)
    invoices       = get_invoice(customer_email, dispute.get("customer_id"), dispute.get("amount"))
    charge_history = get_charge_history(dispute.get("customer_id",""), customer_email)

    # Try to identify the specific location this charge applies to
    disputed_loc = get_disputed_location(invoices, all_locs) or loc

    verdict = determine_verdict(dispute.get("reason"), disputed_loc.get("archived_at") if disputed_loc else None,
                                dispute.get("evidence_due_date"), dispute.get("created_at"))
    signals = evaluate_signals(dispute, user, loc, act_summary, active_dates, last_active, charge_history)
    slug = dispute_id.replace("_","-")
    pkg = {
        slug + "_1_dispute_narrative.pdf":         pdf_narrative(dispute, user, disputed_loc, verdict, act_summary, active_dates, last_active, all_locations, charge_history, signals),
        slug + "_2_dispute_receipt.pdf":            pdf_receipt(dispute, invoices),
        slug + "_3_service_documentation.pdf":      pdf_service_docs(dispute, user, loc, plan_history, all_locations),
        slug + "_4_refund_cancellation_policy.pdf": pdf_policy(dispute, loc),
    }
    pkg["_signals"]     = signals
    pkg["_verdict"]     = verdict
    pkg["_archived_at"] = (fmt(disputed_loc.get("archived_at")) if disputed_loc else None) or "--"

    # Check if the disputed location needs action:
    # Flag if it is NOT canceled OR still above Tier 1
    needs_downgrade = []
    dl = disputed_loc or loc
    if dl:
        not_canceled = not dl.get("archived_at")
        above_tier1  = str(dl.get("tier_id","1")) != "1"
        if not_canceled or above_tier1:
            needs_downgrade.append({
                "location_id": dl.get("location_id"),
                "name":        dl.get("name","Unknown"),
                "tier_id":     dl.get("tier_id"),
                "company_id":  dl.get("company_id") or (loc.get("company_id") if loc else None),
                "not_canceled": not_canceled,
                "above_tier1":  above_tier1,
            })
    pkg["_needs_downgrade"] = needs_downgrade
    pkg["_company_id"]      = loc.get("company_id") if loc else None
    return pkg

