@app.callback(
    Output("status-output","children"),
    Output("download-section","children"),
    Output("pdf-store","data"),
    Input("generate-btn","n_clicks"),
    State("dispute-input","value"),
    prevent_initial_call=True,
)
def on_generate(n_clicks, dispute_id):
    if not dispute_id or not dispute_id.strip():
        return (html.Div("Please enter a dispute ID.",
                        style={"color":"#dc2626","fontSize":"13px"}),
                [], None)
    # Clear previous results immediately so old content doesnt persist
    try:
        pdfs      = build_package(dispute_id.strip())
        import base64
        # Exclude _signals (not a PDF) from the download store
        store = {fn: base64.b64encode(data).decode() for fn, data in pdfs.items() if not fn.startswith("_")}
        filenames = list(store.keys())

        # Show download buttons using the pre-declared IDs in the layout
        rows = []
        for i, (fn, (label, cat)) in enumerate(zip(filenames, STRIPE_UPLOAD_CATEGORIES)):
            rows.append(html.Div([
                html.Div([
                    html.Span(str(i+1) + ". " + label,
                              style={"fontSize":"13px","fontWeight":"600","color":"#111827"}),
                    html.Span(" - upload as: ", style={"fontSize":"12px","color":"#9ca3af"}),
                    html.Code(cat, style={"fontSize":"11px","background":"#eff6ff",
                                         "color":"#4f46e5","padding":"1px 6px","borderRadius":"4px"}),
                ], style={"marginBottom":"6px"}),
                html.Div(fn, style={"fontSize":"11px","color":"#9ca3af","fontFamily":"monospace","marginBottom":"6px"}),
            ], style={"background":"#fff","border":"1px solid #e5e7eb","borderRadius":"10px",
                      "padding":"12px 16px","marginBottom":"8px"}))

        # Download All button + individual buttons
        dl_buttons = html.Div([
            html.Button(
                "⬇  Download All (ZIP)",
                id="dl-btn-all", n_clicks=0,
                style={"display":"block","width":"100%","textAlign":"center",
                       "padding":"12px 14px","marginBottom":"12px",
                       "background":"#0f172a","color":"#f1f5f9",
                       "border":"none","borderRadius":"8px",
                       "fontSize":"14px","fontWeight":"700","cursor":"pointer"}
            ),
            html.Div("Or download individually:", style={"fontSize":"12px","color":"#6b7280","marginBottom":"8px"}),
            html.Div([
                html.Button(str(i+1) + ". " + STRIPE_UPLOAD_CATEGORIES[i][0],
                           id="dl-btn-" + str(i+1), n_clicks=0,
                           style={"display":"block","width":"100%","textAlign":"left",
                                  "padding":"10px 14px","marginBottom":"6px",
                                  "background":"#f8fafc","border":"1px solid #e2e8f0",
                                  "borderRadius":"8px","fontSize":"13px","cursor":"pointer"})
                for i in range(4)
            ]),
        ])

        # Build signals UI from the signals dict stored in pdf package
        sig      = pdfs.get("_signals", {})
        strength = sig.get("strength", "strong")
        warnings = sig.get("warnings", [])
        verdict  = pdfs.get("_verdict") or "NEVER_CANCELED"

        # Check if we should concede
        if verdict == "REFUND_OWED":
            archived = pdfs.get("_archived_at","--")
            status = html.Div([
                html.Div("⚠ ACCEPT THIS DISPUTE",
                         style={"fontWeight":"800","fontSize":"16px","color":"#991b1b","marginBottom":"8px"}),
                html.Div("This account was canceled within the 30-day refund window.",
                         style={"fontSize":"13px","color":"#991b1b","marginBottom":"4px"}),
                html.Div("Cancellation date: " + str(archived),
                         style={"fontSize":"13px","color":"#7f1d1d","marginBottom":"4px"}),
                html.Div("Action required: Issue a full refund and accept the dispute in Stripe.",
                         style={"fontSize":"13px","fontWeight":"600","color":"#7f1d1d"}),
            ], style={"background":"#fef2f2","border":"2px solid #f87171",
                      "borderRadius":"8px","padding":"16px","marginBottom":"12px"})
        else:
            sig_bg  = "#f0fdf4" if strength == "strong" else ("#fffbeb" if strength == "moderate" else "#fef2f2")
            sig_bdr = "#a7f3d0" if strength == "strong" else ("#fcd34d" if strength == "moderate" else "#fecaca")
            sig_col = "#065f46" if strength == "strong" else ("#92400e" if strength == "moderate" else "#991b1b")
            sig_lbl = get_strength_badge(sig)

            warning_items = []
            for w in warnings:
                if w == "no_activity":
                    warning_items.append(html.Li("No platform activity found -- consider not filing", style={"color":"#991b1b"}))
                elif w == "low_activity":
                    warning_items.append(html.Li("Low activity (" + str(sig.get("total_active_days",0)) + " days) -- weak service delivery argument", style={"color":"#92400e"}))
                elif w.startswith("recency_gap_"):
                    gap = w.replace("recency_gap_","")
                    warning_items.append(html.Li(gap + "-day gap between last activity and charge date", style={"color":"#92400e"}))
                elif w == "visa_132_risk":
                    warning_items.append(html.Li("Visa 13.2 risk -- check Salesforce for phone cancellation attempts before filing", style={"color":"#991b1b","fontWeight":"600"}))

            status = html.Div([
                html.Div([
                    html.Span("Package ready  |  ", style={"color":"#16a34a","fontWeight":"700"}),
                    html.Span(dispute_id.strip(), style={"color":"#065f46","fontSize":"13px"}),
                ]),
                html.Div([
                    html.Span("Case strength: ", style={"fontWeight":"600","fontSize":"12px"}),
                    html.Span(sig_lbl, style={"fontSize":"12px","color":sig_col,"fontWeight":"700"}),
                ], style={"marginTop":"6px"}),
                html.Ul(warning_items, style={"marginTop":"6px","marginBottom":"0","paddingLeft":"20px","fontSize":"12px"}) if warning_items else None,
            ], style={"background":sig_bg,"border":"1px solid " + sig_bdr,
                      "borderRadius":"8px","padding":"12px 14px","marginBottom":"12px"})

        # Downgrade alerts
        needs_downgrade = pdfs.get("_needs_downgrade", [])
        if needs_downgrade:
            dg_items = []
            for nd in needs_downgrade:
                company_id  = nd.get("company_id") or pdfs.get("_company_id","")
                location_id = nd.get("location_id","")
                admin_url   = "https://app.joinhomebase.com/admin/companies/" + str(company_id) + "/locations/" + str(location_id)
                dg_items.append(html.Div([
                    html.Span("ACTION REQUIRED: ",
                              style={"fontWeight":"800","color":"#991b1b"}),
                    html.Span(str(nd.get("name","")) + " (ID: " + str(location_id) + ") ",
                              style={"color":"#7f1d1d"}),
                    html.Span(
                        ("is not canceled" if nd.get("not_canceled") else "") +
                        (" and " if nd.get("not_canceled") and nd.get("above_tier1") else "") +
                        ("still on " + tier_name(nd.get("tier_id")) if nd.get("above_tier1") else "") +
                        " -- action required. ",
                        style={"color":"#7f1d1d"}),
                    html.A("Downgrade now →", href=admin_url, target="_blank",
                           style={"color":"#991b1b","fontWeight":"700",
                                  "textDecoration":"underline"}),
                ], style={"marginBottom":"4px","fontSize":"12px"}))

            status = html.Div([
                status,
                html.Div([
                    html.Div("LOCATIONS REQUIRING DOWNGRADE",
                             style={"fontWeight":"800","fontSize":"12px",
                                    "color":"#991b1b","marginBottom":"6px",
                                    "letterSpacing":"0.05em"}),
                    *dg_items,
                ], style={"background":"#fef2f2","border":"2px solid #f87171",
                           "borderRadius":"8px","padding":"12px 14px","marginTop":"8px"}),
            ])

        return status, rows + [dl_buttons], store

    except Exception as e:
        return (
            html.Div([html.Span("Error: ", style={"fontWeight":"700"}), html.Span(str(e))],
                     style={"background":"#fef2f2","border":"1px solid #fecaca",
                            "borderRadius":"8px","padding":"10px 14px",
                            "color":"#991b1b","fontSize":"13px"}),
            [], None,
        )


@app.callback(Output("dl-1","data"), Input("dl-btn-1","n_clicks"),
              State("pdf-store","data"), prevent_initial_call=True)
def dl1(n, store):
    return _download(n, store, 0)

@app.callback(Output("dl-2","data"), Input("dl-btn-2","n_clicks"),
              State("pdf-store","data"), prevent_initial_call=True)
def dl2(n, store):
    return _download(n, store, 1)

@app.callback(Output("dl-3","data"), Input("dl-btn-3","n_clicks"),
              State("pdf-store","data"), prevent_initial_call=True)
def dl3(n, store):
    return _download(n, store, 2)

@app.callback(Output("dl-4","data"), Input("dl-btn-4","n_clicks"),
              State("pdf-store","data"), prevent_initial_call=True)
def dl4(n, store):
    return _download(n, store, 3)

@app.callback(Output("dl-all","data"), Input("dl-btn-all","n_clicks"),
              State("pdf-store","data"), prevent_initial_call=True)
def dl_all(n, store):
    if not store or not n:
        return dash.no_update
    import base64, zipfile, io as _io
    zip_buf = _io.BytesIO()
    with zipfile.ZipFile(zip_buf, "w", zipfile.ZIP_DEFLATED) as zf:
        for fn, b64data in store.items():
            zf.writestr(fn, base64.b64decode(b64data))
    zip_buf.seek(0)
    # Use first filename to derive dispute slug for the zip name
    first_fn = list(store.keys())[0]
    slug = first_fn.split("_1_")[0] if "_1_" in first_fn else "dispute"
    return dcc.send_bytes(zip_buf.read(), filename=slug + "_evidence_package.zip")

def _download(n, store, idx):
    if not store or not n:
        return dash.no_update
    import base64
    keys = list(store.keys())
    if idx >= len(keys):
        return dash.no_update
    return dcc.send_bytes(base64.b64decode(store[keys[idx]]), filename=keys[idx])


